function FriendListItem ({options}) {
  return (
    <ul className="friend-list">
        <li key={option.id} className="item">
          <span className="status">{options.isOnline}</span>
          <img className="avatar" src={options.avatar} alt={option.name} width="48" />
          <p className="name">{options.name}</p>
      </li>
    </ul>
  )
}
export default FriendListItem
